    public void handleOrderBook(Client client, Object message)
    {
        //
        // spot
        //
        //     {
        //         "code":0,
        //         "data":
        //         {
        //             "asks":[
        //                 ["84119.73","0.000011"],
        //                 ["84116.52","0.000014"],
        //                 ["84116.40","0.000039"]
        //             ],
        //             "bids":[
        //                 ["83656.98","2.570805"],
        //                 ["83655.51","0.000347"],
        //                 ["83654.59","0.000082"]
        //             ],
        //             "lastUpdateId":13565694850
        //         },
        //         "dataType":"BTC-USDT@depth100",
        //         "success":true,
        //         "timestamp":1743241379958
        //     }
        //
        // linear swap
        //
        //     {
        //         "code":0,
        //         "dataType":"BTC-USDT@depth100@500ms",
        //         "ts":1743241563651,
        //         "data":
        //         {
        //             "bids":[
        //                 ["83363.2","0.1908"],
        //                 ["83360.0","0.0003"],
        //                 ["83356.5","0.0245"],
        //             ],
        //             "asks":[
        //                 ["83495.0","0.0024"],
        //                 ["83490.0","0.0001"],
        //                 ["83488.0","0.0004"],
        //             ]
        //         }
        //     }
        //
        // inverse swap
        //
        //     {
        //         "code":0,
        //         "dataType":"BTC-USD@depth100",
        //         "data":{
        //             "symbol":"BTC-USD",
        //             "bids":[
        //                 {"p":"83411.2","a":"2.979216","v":"2485.0"},
        //                 {"p":"83411.1","a":"1.592114","v":"1328.0"},
        //                 {"p":"83410.8","a":"2.656730","v":"2216.0"},
        //             ],
        //             "asks":[
        //                 {"p":"88200.0","a":"0.344671","v":"304.0"},
        //                 {"p":"88023.8","a":"0.045442","v":"40.0"},
        //                 {"p":"88001.0","a":"0.003409","v":"3.0"},
        //             ],
        //             "aggPrecision":"0.1",
        //             "timestamp":1743242290710
        //         }
        //     }
        //
        Object data = this.safeDict(message, "data", new java.util.HashMap<String, Object>() {{}});
        Object dataType = this.safeString(message, "dataType", "");
        Object parts = Helpers.split(dataType, "@");
        Object firstPart = Helpers.GetValue(parts, 0);
        Object isAllEndpoint = (Helpers.isEqual(firstPart, "all"));
        Object marketId = this.safeString(data, "symbol", firstPart);
        Object isSwap = Helpers.isGreaterThanOrEqual(Helpers.getIndexOf(client.url, "swap"), 0);
        Object marketType = ((Helpers.isTrue(isSwap))) ? "swap" : "spot";
        Object market = this.safeMarket(marketId, null, null, marketType);
        Object symbol = Helpers.GetValue(market, "symbol");
        Object orderbook = this.safeValue(this.orderbooks, symbol);
        if (Helpers.isTrue(Helpers.isEqual(orderbook, null)))
        {
            // const limit = [ 5, 10, 20, 50, 100 ]
            Object subscriptionHash = dataType;
            Object subscription = Helpers.GetValue(client.subscriptions, ((String)subscriptionHash));
            // see handleOHLCV — subscription.limit may be missing for non-orderbook callers;
            // default to a reasonable depth instead of throwing NPE in the Java port.
            Object limit = this.safeInteger(subscription, "limit", 100);
            Helpers.addElementToObject(this.orderbooks, symbol, this.orderBook(new java.util.HashMap<String, Object>() {{}}, limit));
        }
        orderbook = Helpers.GetValue(this.orderbooks, symbol);
        Object snapshot = null;
        Object timestamp = this.safeInteger2(message, "timestamp", "ts");
        timestamp = this.safeInteger2(data, "timestamp", "ts", timestamp);
        if (Helpers.isTrue(Helpers.GetValue(market, "inverse")))
        {
            snapshot = this.parseOrderBook(data, symbol, timestamp, "bids", "asks", "p", "a");
        } else
        {
            snapshot = this.parseOrderBook(data, symbol, timestamp, "bids", "asks", 0, 1);
        }
        Object nonce = this.safeInteger(data, "lastUpdateId");
        Helpers.addElementToObject(snapshot, "nonce", nonce);
        Helpers.callDynamically(orderbook, "reset", new Object[]{snapshot});
        Object messageHash = this.getMessageHash("orderbook", symbol);
        client.resolve(orderbook, messageHash);
        // resolve for "all"
        if (Helpers.isTrue(isAllEndpoint))
        {
            Object messageHashForAll = this.getMessageHash("orderbook");
            client.resolve(orderbook, messageHashForAll);
        }
    }

    public Object parseWsOHLCV(Object ohlcv, Object... optionalArgs)
    {
        //
        //    {
        //        "c": "28909.0",
        //        "o": "28915.4",
        //        "h": "28915.4",
        //        "l": "28896.1",
        //        "v": "27.6919",
        //        "T": 1696687499999,
        //        "t": 1696687440000
        //    }
        //
        // for spot, opening-time (t) is used instead of closing-time (T), to be compatible with fetchOHLCV
        // for linear swap, (T) is the opening time
        Object market = Helpers.getArg(optionalArgs, 0, null);
        Object timestamp = ((Helpers.isTrue((this.safeBool(market, "spot"))))) ? "t" : "T";
        if (Helpers.isTrue(this.safeBool(market, "swap")))
        {
            timestamp = ((Helpers.isTrue((this.safeBool(market, "inverse"))))) ? "t" : "T";
        }
        return new java.util.ArrayList<Object>(java.util.Arrays.asList(this.safeInteger(ohlcv, timestamp), this.safeNumber(ohlcv, "o"), this.safeNumber(ohlcv, "h"), this.safeNumber(ohlcv, "l"), this.safeNumber(ohlcv, "c"), this.safeNumber(ohlcv, "v")));
    }

    public void handleOHLCV(Client client, Object message)
    {
        //
        // spot:
        //
        //   {
        //       "code": 0,
        //       "data": {
        //         "E": 1696687498608,
        //         "K": {
        //           "T": 1696687499999,
        //           "c": "27917.829",
        //           "h": "27918.427",
        //           "i": "1min",
        //           "l": "27917.7",
        //           "n": 262,
        //           "o": "27917.91",
        //           "q": "25715.359197",
        //           "s": "BTC-USDT",
        //           "t": 1696687440000,
        //           "v": "0.921100"
        //         },
        //         "e": "kline",
        //         "s": "BTC-USDT"
        //       },
        //       "dataType": "BTC-USDT@kline_1min",
        //       "success": true
        //   }
        //
        // linear swap:
        //
        //    {
        //        "code": 0,
        //        "dataType": "BTC-USDT@kline_1m",
        //        "s": "BTC-USDT",
        //        "data": [
        //            {
        //            "c": "28909.0",
        //            "o": "28915.4",
        //            "h": "28915.4",
        //            "l": "28896.1",
        //            "v": "27.6919",
        //            "T": 1690907580000
        //            }
        //        ]
        //    }
        //
        // inverse swap:
        //
        //     {
        //         "code": 0,
        //         "timestamp": 1723769354547,
        //         "dataType": "BTC-USD@kline_1m",
        //         "data": {
        //             "t": 1723769340000,
        //             "o": 57485.1,
        //             "c": 57468,
        //             "l": 57464.9,
        //             "h": 57485.1,
        //             "a": 0.189663,
        //             "v": 109,
        //             "u": 92,
        //             "s": "BTC-USD"
        //         }
        //     }
        //
        Object isSwap = Helpers.isGreaterThanOrEqual(Helpers.getIndexOf(client.url, "swap"), 0);
        Object dataType = this.safeString(message, "dataType", "");
        Object parts = Helpers.split(dataType, "@");
        Object firstPart = Helpers.GetValue(parts, 0);
        Object isAllEndpoint = (Helpers.isEqual(firstPart, "all"));
        Object marketId = this.safeString(message, "s", firstPart);
        Object marketType = ((Helpers.isTrue(isSwap))) ? "swap" : "spot";
        Object market = this.safeMarket(marketId, null, null, marketType);
        Object candles = null;
        if (Helpers.isTrue(isSwap))
        {
            if (Helpers.isTrue(Helpers.GetValue(market, "inverse")))
            {
                candles = new java.util.ArrayList<Object>(java.util.Arrays.asList(this.safeDict(message, "data", new java.util.HashMap<String, Object>() {{}})));
            } else
            {
                candles = this.safeList(message, "data", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
            }
        } else
        {
            Object data = this.safeDict(message, "data", new java.util.HashMap<String, Object>() {{}});
            candles = new java.util.ArrayList<Object>(java.util.Arrays.asList(this.safeDict(data, "K", new java.util.HashMap<String, Object>() {{}})));
        }
        Object symbol = Helpers.GetValue(market, "symbol");
        Helpers.addElementToObject(this.ohlcvs, symbol, this.safeValue(this.ohlcvs, symbol, new java.util.HashMap<String, Object>() {{}}));
        Object rawTimeframe = Helpers.GetValue(Helpers.split(dataType, "_"), 1);
        Object marketOptions = this.safeDict(this.options, marketType);
        Object timeframes = this.safeDict(marketOptions, "timeframes", new java.util.HashMap<String, Object>() {{}});
        Object unifiedTimeframe = this.findTimeframe(rawTimeframe, timeframes);
        if (Helpers.isTrue(Helpers.isEqual(this.safeValue(Helpers.GetValue(this.ohlcvs, symbol), rawTimeframe), null)))
        {
            Object subscriptionHash = dataType;
            Object subscription = Helpers.GetValue(client.subscriptions, ((String)subscriptionHash));
            // subscription.limit is only set when watchOHLCV registers the subscription;
            // when handleMessage routes a non-OHLCV-originated subscription here (or the
            // subscription dict was reset on reconnect), fall back to the OHLCVLimit option.
            Object limit = this.safeInteger(subscription, "limit", this.safeInteger(this.options, "OHLCVLimit", 1000));
            Helpers.addElementToObject(Helpers.GetValue(this.ohlcvs, symbol), ((String)unifiedTimeframe), new ArrayCache.ArrayCacheByTimestamp(((Number)limit).intValue()));
        }
        Object stored = Helpers.GetValue(Helpers.GetValue(this.ohlcvs, symbol), ((String)unifiedTimeframe));
        for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(candles)); i++)
        {
            Object candle = Helpers.GetValue(candles, i);
            Object parsed = this.parseWsOHLCV(candle, market);
            Helpers.callDynamically(stored, "append", new Object[]{parsed});
        }
        Object resolveData = new java.util.ArrayList<Object>(java.util.Arrays.asList(symbol, unifiedTimeframe, stored));
        Object messageHash = this.getMessageHash("ohlcv", symbol, unifiedTimeframe);
        client.resolve(resolveData, messageHash);
        // resolve for "all"
        if (Helpers.isTrue(isAllEndpoint))
        {
            Object messageHashForAll = this.getMessageHash("ohlcv", null, unifiedTimeframe);
            client.resolve(resolveData, messageHashForAll);
        }
    }

