    public java.util.concurrent.CompletableFuture<Object> loadPositionsSnapshot(Client client, Object messageHash2, Object type)
    {
        final Object messageHash3 = messageHash2;
        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {
            Object messageHash = messageHash3;
            Object positions = (this.fetchPositions((Object)(null), (Object)((Object) new java.util.HashMap<String, Object>() {{
                put( "type", type );
                put( "subType", "linear" );
            }}))).join();
            this.positions = new ArrayCache.ArrayCacheBySymbolBySide();
            Object cache = this.positions;
            for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(positions)); i++)
            {
                Object position = Helpers.GetValue(positions, i);
                Object contracts = this.safeNumber(position, "contracts", 0);
                if (Helpers.isTrue(Helpers.isGreaterThan(contracts, 0)))
                {
                    Helpers.callDynamically(cache, "append", new Object[]{position});
                }
            }
            // don't remove the future from the .futures cache
            if (Helpers.isTrue(Helpers.inOp(client.futures, messageHash)))
            {
                io.github.ccxt.ws.Future future = (io.github.ccxt.ws.Future)Helpers.GetValue(client.futures, messageHash);
                ((io.github.ccxt.ws.Future)future).resolve(cache);
                client.resolve(cache, "swap:positions");
            }
            return null;
        });

    }

    public Object parseWsPosition(Object position, Object... optionalArgs)
    {
        //
        //     {
        //         "s": "LINK-USDT",     // Symbol
        //         "pa": "5.000",        // Position Amount
        //         "ep": "11.2345",      // Entry Price
        //         "up": "0.5000",       // Unrealized PnL
        //         "mt": "isolated",     // Margin Type
        //         "iw": "50.00000000",  // Isolated Wallet
        //         "ps": "LONG"          // Position Side
        //     }
        //
        Object market = Helpers.getArg(optionalArgs, 0, null);
        Object marketId = this.safeString(position, "s");
        Object contracts = this.safeString(position, "pa");
        Object contractsAbs = Precise.stringAbs(contracts);
        Object positionSide = this.safeStringLower(position, "ps");
        Object hedged = true;
        if (Helpers.isTrue(Helpers.isEqual(positionSide, "both")))
        {
            hedged = false;
            if (!Helpers.isTrue(Precise.stringEq(contracts, "0")))
            {
                if (Helpers.isTrue(Precise.stringLt(contracts, "0")))
                {
                    positionSide = "short";
                } else
                {
                    positionSide = "long";
                }
            }
        }
        Object marginMode = this.safeString(position, "mt");
        Object collateral = ((Helpers.isTrue((Helpers.isEqual(marginMode, "isolated"))))) ? this.safeNumber(position, "iw") : null;
        final Object finalMarginMode = marginMode;
        final Object finalPositionSide = positionSide;
        final Object finalHedged = hedged;
        return this.safePosition(new java.util.HashMap<String, Object>() {{
            put( "info", position );
            put( "id", null );
            put( "symbol", BingxCore.this.safeSymbol(marketId, null, null, "swap") );
            put( "notional", null );
            put( "marginMode", finalMarginMode );
            put( "liquidationPrice", null );
            put( "entryPrice", BingxCore.this.safeNumber(position, "ep") );
            put( "unrealizedPnl", BingxCore.this.safeNumber(position, "up") );
            put( "percentage", null );
            put( "contracts", BingxCore.this.parseNumber(contractsAbs) );
            put( "contractSize", null );
            put( "markPrice", null );
            put( "side", finalPositionSide );
            put( "hedged", finalHedged );
            put( "timestamp", null );
            put( "datetime", null );
            put( "maintenanceMargin", null );
            put( "maintenanceMarginPercentage", null );
            put( "collateral", collateral );
            put( "initialMargin", null );
            put( "initialMarginPercentage", null );
            put( "leverage", null );
            put( "marginRatio", null );
        }});
    }

    public void handlePositions(Client client, Object message)
    {
        //
        //     {
        //         "e": "ACCOUNT_UPDATE",
        //         "E": 1696244249320,
        //         "a": {
        //             "m": "ORDER",
        //             "B": [...],
        //             "P": [
        //                 {
        //                     "s": "LINK-USDT",
        //                     "pa": "5.000",
        //                     "ep": "11.2345",
        //                     "up": "0.5000",
        //                     "mt": "isolated",
        //                     "iw": "50.00000000",
        //                     "ps": "LONG"
        //                 }
        //             ]
        //         }
        //     }
        //
        if (Helpers.isTrue(Helpers.isEqual(this.positions, null)))
        {
            this.positions = new ArrayCache.ArrayCacheBySymbolBySide();
        }
        Object cache = this.positions;
        Object data = this.safeDict(message, "a", new java.util.HashMap<String, Object>() {{}});
        Object rawPositions = this.safeList(data, "P", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
        Object newPositions = new java.util.ArrayList<Object>(java.util.Arrays.asList());
        for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(rawPositions)); i++)
        {
            Object rawPosition = Helpers.GetValue(rawPositions, i);
            Object position = this.parseWsPosition(rawPosition);
            Object symbol = this.safeString(position, "symbol");
            if (Helpers.isTrue(Helpers.isEqual(symbol, null)))
            {
                continue;
            }
            Object timestamp = this.safeInteger(message, "E");
            Helpers.addElementToObject(position, "timestamp", timestamp);
            Helpers.addElementToObject(position, "datetime", this.iso8601(timestamp));
            ((java.util.List<Object>)newPositions).add(position);
            Helpers.callDynamically(cache, "append", new Object[]{position});
        }
        Object messageHashes = this.findMessageHashes(client, "swap:positions::");
        for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(messageHashes)); i++)
        {
            Object messageHash = Helpers.GetValue(messageHashes, i);
            Object parts = Helpers.split(messageHash, "::");
            Object symbolsString = Helpers.GetValue(parts, 1);
            Object filteredSymbols = Helpers.split(symbolsString, ",");
            Object positions = this.filterByArray(newPositions, "symbol", filteredSymbols, false);
            if (!Helpers.isTrue(this.isEmpty(positions)))
            {
                client.resolve(positions, messageHash);
            }
        }
        client.resolve(newPositions, "swap:positions");
    }

    public Object handleErrorMessage(Client client, Object message)
    {
        //
        // { code: 100400, msg: '', timestamp: 1696245808833 }
        //
        // {
        //     "code": 100500,
        //     "id": "9cd37d32-da98-440b-bd04-37e7dbcf51ad",
        //     "msg": '',
        //     "timestamp": 1696245842307
        // }
        Object code = this.safeString(message, "code");
        try
        {
            if (Helpers.isTrue(!Helpers.isEqual(code, null)))
            {
                Object feedback = Helpers.add(Helpers.add(this.id, " "), this.json(message));
                this.throwExactlyMatchedException(Helpers.GetValue(this.exceptions, "exact"), code, feedback);
            }
        } catch(Exception e)
        {
            client.reject(e);
        }
        return true;
    }

    public java.util.concurrent.CompletableFuture<Object> keepAliveListenKey(Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object parameters = Helpers.getArg(optionalArgs, 0, new java.util.HashMap<String, Object>() {{}});
            Object listenKey = this.safeString(this.options, "listenKey");
            if (Helpers.isTrue(Helpers.isEqual(listenKey, null)))
            {
                // A network error happened: we can't renew a listen key that does not exist.
                return null;
            }
            try
            {
                (this.userAuthPrivatePutUserDataStream(new java.util.HashMap<String, Object>() {{
                    put( "listenKey", listenKey );
                }})).join(); // extend the expiry
            } catch(Exception error)
            {
                Object types = new java.util.ArrayList<Object>(java.util.Arrays.asList("spot", "linear", "inverse"));
                for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(types)); i++)
                {
                    Object type = Helpers.GetValue(types, i);
                    Object baseUrl = this.safeString(Helpers.GetValue(Helpers.GetValue(this.urls, "api"), "ws"), type);
                    if (Helpers.isTrue(Helpers.isEqual(baseUrl, null)))
                    {
                        continue;
                    }
                    Object url = Helpers.add(Helpers.add(baseUrl, "?listenKey="), listenKey);
                    Client client = this.client(url);
                    Object messageHashes = Helpers.objectKeys(client.futures);
                    for (var j = 0; Helpers.isLessThan(j, Helpers.getArrayLength(messageHashes)); j++)
                    {
                        Object messageHash = Helpers.GetValue(messageHashes, j);
                        client.reject(error, messageHash);
                    }
                }
                Helpers.addElementToObject(this.options, "listenKey", null);
                Helpers.addElementToObject(this.options, "lastAuthenticatedTime", 0);
                return null;
            }
            // whether or not to schedule another listenKey keepAlive request
            Object listenKeyRefreshRate = this.safeInteger(this.options, "listenKeyRefreshRate", 3600000);
            this.scheduleCallback(listenKeyRefreshRate, "keepAliveListenKey", parameters);
            return null;
        });

    }

    public java.util.concurrent.CompletableFuture<Object> authenticate(Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object parameters = Helpers.getArg(optionalArgs, 0, new java.util.HashMap<String, Object>() {{}});
            Object time = this.milliseconds();
            Object lastAuthenticatedTime = this.safeInteger(this.options, "lastAuthenticatedTime", 0);
            Object listenKeyRefreshRate = this.safeInteger(this.options, "listenKeyRefreshRate", 3600000); // 1 hour
            if (Helpers.isTrue(Helpers.isGreaterThan(Helpers.subtract(time, lastAuthenticatedTime), listenKeyRefreshRate)))
            {
                Object response = (this.userAuthPrivatePostUserDataStream()).join();
                Helpers.addElementToObject(this.options, "listenKey", this.safeString(response, "listenKey"));
                Helpers.addElementToObject(this.options, "lastAuthenticatedTime", time);
                this.scheduleCallback(listenKeyRefreshRate, "keepAliveListenKey", parameters);
            }
            return null;
        });

    }

    public java.util.concurrent.CompletableFuture<Object> pong(Client client, Object message2)
    {
        final Object message3 = message2;
        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {
            Object message = message3;
            try
            {
                if (Helpers.isTrue(Helpers.isEqual(message, "Ping")))
                {
                    (client.send("Pong")).join();
                } else
                {
                    Object ping = this.safeString(message, "ping");
                    Object time = this.safeString(message, "time");
                    (client.send(new java.util.HashMap<String, Object>() {{
                        put( "pong", ping );
                        put( "time", time );
                    }})).join();
                }
            } catch(Exception e)
            {
                var error = new NetworkError(Helpers.add(Helpers.add(this.id, " pong failed with error "), this.exceptionMessage(e)));
                client.reset(error);
            }
            return null;
        });

    }

